// /frontend/src/components/Composer.jsx
import React, { useState } from "react";

export default function Composer({ onPost, maxLen = 280, placeholder = "What’s happening?" }) {
  const [text, setText] = useState("");

  const submit = () => {
    const t = text.trim();
    if (!t) return;
    onPost?.(t);
    setText("");
  };

  const count = text.length;
  const over = count > maxLen;

  return (
    <div className="flex gap-3">
      {/* avatar */}
      <div className="h-10 w-10 rounded-full bg-white/20 shrink-0 grid place-items-center">🟣</div>

      <div className="flex-1">
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          rows={3}
          className="w-full bg-transparent outline-none resize-none text-sm"
          placeholder={placeholder}
          maxLength={maxLen + 40} // allow a bit over; we'll block on submit if needed
        />

        <div className="flex items-center justify-between mt-2">
          <div className="text-xs opacity-60">{count}/{maxLen}</div>
          <button
            onClick={submit}
            disabled={!text.trim() || over}
            className="px-3 py-1.5 rounded-lg bg-white/15 ring-1 ring-white/10 disabled:opacity-50 text-sm"
          >
            Post
          </button>
        </div>
      </div>
    </div>
  );
}
